108→/// Strip `root` prefix from `path` to produce a relative path string.
109→/// Falls back to the full path if stripping fails.
110→fn relativize_path(path: &Path, root: &Path) -> String {
111→    path.strip_prefix(root)
112→        .unwrap_or(path)
113→        .to_string_lossy()
114→        .into_owned()
